function solve(weight: number[]): number {
    let maxCount = 0;
    let start = 0;

    for (let end = 0; end < weight.length; end++) {
        // Keep expanding the window until the condition is met
        while (start <= end) {
            // Check if the current window is a balanced shipment
            const currentMax = Math.max(...weight.slice(start, end + 1));
            if (weight[end] < currentMax) {
                maxCount++;
                break;
            }
            // Move the start pointer to the right
            start++;
        }
    }

    return maxCount;
}
